#!/bin/bash
whois "$1" | awk -F': ' '/^(Registrant|Admin|Tech) Name:/{print $1","$2} /^(Registrant|Admin|Tech) Organization:/{print $1","$2} /^(Registrant|Admin|Tech) Street:/{print $1","$2" "} /^(Registrant|Admin|Tech) City:/{print $1","$2} /^(Registrant|Admin|Tech) State\/Province:/{print $1","$2} /^(Registrant|Admin|Tech) Postal Code:/{print $1","$2} /^(Registrant|Admin|Tech) Country:/{print $1","$2} /^(Registrant|Admin|Tech) Phone:/{print $1","$2} /^(Registrant|Admin|Tech) Phone Ext:/{print $1","$2} /^(Registrant|Admin|Tech) Fax:/{print $1","$2} /^(Registrant|Admin|Tech) Fax Ext:/{print $1","$2} /^(Registrant|Admin|Tech) Email:/{print $1","$2}' > "$1.csv"
